   574→    HttpStreamIdProviderImpl(ActiveStream& parent) : parent_(parent) {}
   575→
   576→    // StreamInfo::StreamIdProvider
   577→    absl::optional<absl::string_view> toStringView() const override;
   578→    absl::optional<uint64_t> toInteger() const override;
   579→
   580→    ActiveStream& parent_;
   581→  };
   582→
   583→  /**
   584→   * Check to see if the connection can be closed after gracefully waiting to send pending codec
   585→   * data.
   586→   */
   587→  void checkForDeferredClose(bool skip_deferred_close);
   588→
   589→  /**
   590→   * Do a delayed destruction of a stream to allow for stack unwind. Also calls onDestroy() for
   591→   * each filter.
   592→   */
   593→  void doDeferredStreamDestroy(ActiveStream& stream);
   594→
   595→  /**
   596→   * Process a stream that is ending due to upstream response or reset.
   597→   * If check_for_deferred_close is true, the ConnectionManager will check to
   598→   * see if the connection was drained and should be closed if no streams remain.
   599→   */
   600→  void doEndStream(ActiveStream& stream, bool check_for_deferred_close = true);
   601→
   602→  void resetAllStreams(absl::optional<StreamInfo::CoreResponseFlag> response_flag,
   603→                       absl::string_view details);
   604→  void onIdleTimeout();
   605→  void onConnectionDurationTimeout();
   606→  void onDrainTimeout();
   607→  void startDrainSequence();
   608→  Tracing::Tracer& tracer() { return *config_->tracer(); }
   609→  void handleCodecErrorImpl(absl::string_view error, absl::string_view details,
   610→                            StreamInfo::CoreResponseFlag response_flag);
   611→  void handleCodecError(absl::string_view error);
   612→  void handleCodecOverloadError(absl::string_view error);
   613→  void doConnectionClose(absl::optional<Network::ConnectionCloseType> close_type,
   614→                         absl::optional<StreamInfo::CoreResponseFlag> response_flag,
   615→                         absl::string_view details);
   616→  void sendGoAwayAndClose(bool graceful = false);
   617→
   618→  // Returns true if a RST_STREAM for the given stream is premature. Premature
   619→  // means the RST_STREAM arrived before response headers were sent and than
   620→  // the stream was alive for short period of time. This period is specified
   621→  // by the optional runtime value PrematureResetMinStreamLifetimeSecondsKey,
   622→  // or one second if that is not present.
   623→  bool isPrematureRstStream(const ActiveStream& stream) const;
   624→  // Sends a GOAWAY if both sufficient streams have been closed on a connection
   625→  // and at least half have been prematurely reset?
   626→  void maybeDrainDueToPrematureResets();
   627→
   628→  bool shouldDeferRequestProxyingToNextIoCycle();
   629→  void onDeferredRequestProcessing();
   630→
   631→  enum class DrainState { NotDraining, Draining, Closing };
   632→
   633→  ConnectionManagerConfigSharedPtr config_;
   634→  ConnectionManagerStats& stats_; // We store a reference here to avoid an extra stats() call on
   635→                                  // the config in the hot path.
   636→  ServerConnectionPtr codec_;
   637→  std::list<ActiveStreamPtr> streams_;
   638→  Stats::TimespanPtr conn_length_;
   639→  const Network::DrainDecision& drain_close_;
   640→  DrainState drain_state_{DrainState::NotDraining};
   641→  UserAgent user_agent_;
   642→  // An idle timer for the connection. This is only armed when there are no streams on the
   643→  // connection. When there are active streams it is disarmed in favor of each stream's
   644→  // stream_idle_timer_.
   645→  Event::TimerPtr connection_idle_timer_;
   646→  // A connection duration timer. Armed during handling new connection if enabled in config.
   647→  Event::TimerPtr connection_duration_timer_;
   648→  Event::TimerPtr drain_timer_;
   649→  // When set to true, add Connection:close response header to nudge downstream client to reconnect.
   650→  bool soft_drain_http1_{false};
   651→  Random::RandomGenerator& random_generator_;
   652→  Runtime::Loader& runtime_;
   653→  const LocalInfo::LocalInfo& local_info_;
   654→  Upstream::ClusterManager& cluster_manager_;
   655→  Network::ReadFilterCallbacks* read_callbacks_{};
   656→  Event::Dispatcher* dispatcher_{};
   657→  ConnectionManagerListenerStats& listener_stats_;
   658→  Server::OverloadManager& overload_manager_;
   659→  Server::ThreadLocalOverloadState& overload_state_;
   660→  Server::LoadShedPoint* accept_new_http_stream_{nullptr};
   661→  Server::LoadShedPoint* hcm_ondata_creating_codec_{nullptr};
   662→  // References into the overload manager thread local state map. Using these lets us avoid a
   663→  // map lookup in the hot path of processing each request.
   664→  const Server::OverloadActionState& overload_stop_accepting_requests_ref_;
   665→  const Server::OverloadActionState& overload_disable_keepalive_ref_;
   666→  TimeSource& time_source_;
   667→  bool go_away_sent_{false};
   668→  bool remote_close_{};
   669→  // Hop by hop headers should always be cleared for Envoy-as-a-proxy but will
   670→  // not be for Envoy-mobile.
   671→  bool clear_hop_by_hop_response_headers_{true};
   672→  // The number of requests accumulated on the current connection.
   673→  uint64_t accumulated_requests_{};
   674→  // The number of requests closed on the current connection which were
   675→  // not internally destroyed
   676→  uint64_t closed_non_internally_destroyed_requests_{};
   677→  // The number of requests that received a premature RST_STREAM, according to
   678→  // the definition given in `isPrematureRstStream()`.
   679→  uint64_t number_premature_stream_resets_{0};
   680→  const std::string proxy_name_; // for Proxy-Status.
   681→  uint32_t requests_during_dispatch_count_{0};
   682→  const uint32_t max_requests_during_dispatch_{UINT32_MAX};
   683→  Event::SchedulableCallbackPtr deferred_request_processing_callback_;
   684→  const envoy::config::core::v3::TrafficDirection direction_;
   685→
   686→  // If independent half-close is enabled and the upstream protocol is either HTTP/2 or HTTP/3
   687→  // protocols the stream is destroyed after both request and response are complete i.e. reach their
   688→  // respective end-of-stream, by receiving trailers or the header/body with end-stream set in both
   689→  // directions AND response has success (2xx) status code.
   690→  //
   691→  // For HTTP/1 upstream protocol or if independent half-close is disabled the stream is destroyed
   692→  // when the response is complete and reaches its end-of-stream, i.e. when trailers or the response
   693→  // header/body with end-stream set are received, even if the request has not yet completed. If
   694→  // request was incomplete at response completion, the stream is reset.
   695→
   696→  const bool allow_upstream_half_close_{};
   697→  // Whether to call checkForDeferredClose() when zombie streams complete.
   698→  // This fixes a potential FD leak where connections with zombie streams in draining state
   699→  // would not be properly closed.
   700→  const bool close_connection_on_zombie_stream_complete_{};
   701→
   702→  // Whether the connection manager is drained due to premature resets.
   703→  bool drained_due_to_premature_resets_{false};
   704→};
